<?php
declare(strict_types=1);
require __DIR__.'/bootstrap.php';$customer=vp3_require_customer();$projects=[];$briefs=[];$ready=false;
if(vp3_db_available()){try{$stmt=vp3_db()->prepare('SELECT p.*,a.name manager_name,(SELECT COUNT(*) FROM project_tasks t WHERE t.project_id=p.id AND t.status NOT IN (\'completed\',\'cancelled\')) open_tasks,(SELECT COUNT(*) FROM project_approvals pa WHERE pa.project_id=p.id AND pa.status=\'pending\') pending_approvals FROM creative_projects p LEFT JOIN admins a ON a.id=p.project_manager_admin_id WHERE p.customer_id=? ORDER BY p.updated_at DESC');$stmt->execute([$customer['id']]);$projects=$stmt->fetchAll();$stmt=vp3_db()->prepare('SELECT id,project_name,status,target_launch_date,updated_at FROM project_briefs WHERE customer_id=? ORDER BY updated_at DESC');$stmt->execute([$customer['id']]);$briefs=$stmt->fetchAll();$ready=true;}catch(Throwable $e){vp3_log('warning','Project dashboard unavailable',['message'=>$e->getMessage()]);}}
$pageTitle='Projects';require VP3_ROOT.'/includes/account-header.php';?>
<div class="page-head"><div><span class="eyebrow">Creative operations</span><h1>Your projects</h1><p class="helper">Follow discovery, strategy, production, launch readiness, tasks, approvals, and assets.</p></div><a class="button" href="account-project-brief.php">Start a project brief</a></div>
<?php if(!$ready):?><div class="notice">Import the sales and creative operations migration to enable project workspaces.</div><?php else:?><div class="project-grid"><?php foreach($projects as $p):?><article class="project-card"><div class="project-card-top"><span class="badge <?=vp3_e($p['health_status'])?>"><?=vp3_e(str_replace('_',' ',$p['health_status']))?></span><span><?=vp3_e(vp3_project_phase_label($p['phase']))?></span></div><h2><?=vp3_e($p['title'])?></h2><p><?=vp3_e($p['summary'])?></p><div class="readiness"><div><span>Launch readiness</span><strong><?=(int)$p['readiness_percent']?>%</strong></div><i><b style="width:<?=(int)$p['readiness_percent']?>%"></b></i></div><dl class="mini-metrics"><div><dt>Open tasks</dt><dd><?=(int)$p['open_tasks']?></dd></div><div><dt>Approvals</dt><dd><?=(int)$p['pending_approvals']?></dd></div><div><dt>Launch</dt><dd><?=vp3_e($p['target_launch_date']?:'Not set')?></dd></div></dl><a class="button small" href="account-project.php?id=<?=(int)$p['id']?>">Open project</a></article><?php endforeach;?><?php if(!$projects):?><div class="empty-state"><h3>No active project yet</h3><p>Complete a creative brief. VP3 can review it, prepare a proposal, and activate the project workspace.</p><a class="button" href="account-project-brief.php">Create a brief</a></div><?php endif;?></div><section class="section compact-section"><div class="section-heading"><div><span class="eyebrow">Onboarding</span><h2>Project briefs</h2></div></div><div class="table-wrap"><table><thead><tr><th>Brief</th><th>Status</th><th>Target launch</th><th>Updated</th></tr></thead><tbody><?php foreach($briefs as $b):?><tr><td><a href="account-project-brief.php?id=<?=(int)$b['id']?>"><strong><?=vp3_e($b['project_name'])?></strong></a></td><td><span class="badge <?=vp3_e($b['status'])?>"><?=vp3_e(str_replace('_',' ',$b['status']))?></span></td><td><?=vp3_e($b['target_launch_date']?:'—')?></td><td><?=vp3_e($b['updated_at'])?></td></tr><?php endforeach;?><?php if(!$briefs):?><tr><td colspan="4">No project briefs yet.</td></tr><?php endif;?></tbody></table></div></section><?php endif;?>
<?php require VP3_ROOT.'/includes/account-footer.php'; ?>
